function renderProduct(){const t=document.getElementById("pdp");if(!t)return;const e=new URLSearchParams(location.search).get("id"),n=PRODUCTS.find(t=>t.id===e)||PRODUCTS[0];document.title=`${n.name} — ${n.origin} Coffee | Meridian Roasters`,setMeta("description",`${n.blurb} Tasting notes: ${n.notes.join(", ")}. $${n.price} per ${n.weight}, roasted to order.`);const o=document.getElementById("canonical");o&&(o.href=`https://meridianroasters.com/product.html?id=${n.id}`),document.getElementById("crumb-name").textContent=n.name,injectJSONLD({"@context":"https://schema.org","@type":"Product",name:`${n.name} — ${n.origin}`,description:n.blurb,image:`https://meridianroasters.com/${n.image}`,sku:n.id.toUpperCase(),brand:{"@type":"Brand",name:"Meridian Roasters"},category:"Specialty Coffee",offers:{"@type":"Offer",price:n.price.toFixed(2),priceCurrency:"USD",itemCondition:"https://schema.org/NewCondition",availability:n.stock?"https://schema.org/InStock":"https://schema.org/OutOfStock",url:`https://meridianroasters.com/product.html?id=${n.id}`},additionalProperty:[{"@type":"PropertyValue",name:"Roast",value:n.roast},{"@type":"PropertyValue",name:"Process",value:n.process},{"@type":"PropertyValue",name:"Altitude",value:n.altitude}]});const d=n.stock?`<button class="btn btn--copper" id="pdpAdd">Add to cart · $${n.price}</button>`:'<span class="card__soldout">Currently sold out</span>';t.innerHTML=`\n    <div class="pdp__visual">\n      ${productMedia(n,"feature")}\n      <span class="pdp__coords">${n.coords}</span>\n    </div>\n    <div class="pdp__info">\n      <p class="pdp__origin">${n.origin}${n.tag?" · "+n.tag:""}</p>\n      <h1 class="pdp__name">${n.name}</h1>\n      <p class="pdp__price">$${n.price} <small>/ ${n.weight}</small></p>\n      <p class="pdp__blurb">${n.blurb}</p>\n      <div class="pdp__notes">\n        ${n.notes.map(t=>`<span>${t}</span>`).join("")}\n      </div>\n      <table class="spec-table">\n        <tbody>\n          <tr><th scope="row">Roast level</th><td>${n.roast}</td></tr>\n          <tr><th scope="row">Process</th><td>${n.process}</td></tr>\n          <tr><th scope="row">Altitude</th><td>${n.altitude}</td></tr>\n          <tr><th scope="row">Weight</th><td>${n.weight}</td></tr>\n          <tr><th scope="row">Availability</th><td>${n.stock?"In stock · ships in 24h":"Sold out"}</td></tr>\n        </tbody>\n      </table>\n      <div class="pdp__buy">\n        <div class="qty" ${n.stock?"":"hidden"}>\n          <button id="qtyDown" aria-label="Decrease quantity">−</button>\n          <span id="qtyVal">1</span>\n          <button id="qtyUp" aria-label="Increase quantity">+</button>\n        </div>\n        ${d}\n      </div>\n    </div>`;let a=1;const i=document.getElementById("qtyVal");document.getElementById("qtyDown")?.addEventListener("click",()=>{a=Math.max(1,a-1),i.textContent=a}),document.getElementById("qtyUp")?.addEventListener("click",()=>{a+=1,i.textContent=a}),document.getElementById("pdpAdd")?.addEventListener("click",()=>{addToCart(n.id,a),openDrawer()});const r=document.getElementById("related-grid");if(r){const t=PRODUCTS.filter(t=>t.id!==n.id).slice(0,4);r.innerHTML=t.map(productCard).join(""),bindAddButtons(r)}}function setMeta(t,e){let n=document.querySelector(`meta[name="${t}"]`);n||(n=document.createElement("meta"),n.name=t,document.head.appendChild(n)),n.content=e}function injectJSONLD(t){const e=document.createElement("script");e.type="application/ld+json",e.textContent=JSON.stringify(t),document.head.appendChild(e)}